151: 		 */
152: 		Assert(input == NULL || input[inputlen] == '\0');
153: 
154: 		/*
155: 		 * Hand the incoming message to the mechanism implementation.
156: 		 */
157: 		result = mech->exchange(opaq, input, inputlen,
158: 								&output, &outputlen,
159: 								logdetail);
160: 
161: 		/* input buffer no longer used */
162: 		pfree(buf.data);
163: 
164: 		if (output)
