178: 			if (result == PG_SASL_EXCHANGE_SUCCESS)
179: 				sendAuthRequest(port, AUTH_REQ_SASL_FIN, output, outputlen);
180: 			else
181: 				sendAuthRequest(port, AUTH_REQ_SASL_CONT, output, outputlen);
182: 
183: 			pfree(output);
184: 		}
185: 	} while (result == PG_SASL_EXCHANGE_CONTINUE);
